     "desc": "{\n  \"scene\": {\n    \"setting\": \"sunlit grassy field filled with small white daisies\",\n    \"time_of_day\": \"golden hour, late afternoon\",\n    \"environment\": \"lush green grass with scattered wildflowers, soft breeze implied through slight motion blur in grass tips\",\n    \"mood\": \"nostalgic, calm, dreamy, slightly melancholic\"\n  },\n  \"composition\": {\n    \"camera_angle\": \"top-down POV shot (first-person perspective)\",\n    \"framing\": \"legs and feet centered in lower third, UI floating mid-frame\",\n    \"depth\": \"moderate depth of field, foreground sharp, background slightly softened\",\n    \"focus_subject\": \"shoes and holographic music interface\"\n  },\n  \"subject\": {\n    \"appearance\": \"person standing on grass wearing beige pants and clean white sneakers\",\n    \"pose\": \"feet slightly apart, relaxed stance\",\n    \"identity\": \"not visible beyond legs (anonymous POV)\"\n  },\n  \"props\": {\n    \"footwear\": \"minimal white sneakers, slightly worn but clean\",\n    \"clothing\": \"light beige trousers with soft fabric folds\",\n    \"ground_details\": \"dense green grass with scattered small white daisies and occasional yellow highlights\"\n  },\n  \"ui_element\": {\n    \"type\": \"floating holographic music player\",\n    \"style\": \"glassmorphism, semi-transparent panels with soft blur and glow\",\n    \"layout\": \"three horizontal album cards, center card larger and in focus\",\n    \"content\": {\n      \"artist\": \"Lana Del Rey\",\n      \"tracks\": [\n        \"West Coast\",\n        \"Summertime Sadness\",\n        \"Dark Paradise\"\n      ]\n    },\n    \"controls\": \"minimal playback controls (play button, progress bar, skip icons)\",\n    \"effects\": \"soft glow, light refraction, subtle reflections, depth layering\"\n  },\n  \"lighting\": {\n    \"type\": \"natural sunlight\",\n    \"direction\": \"angled from top left\",\n    \"quality\": \"warm, diffused, golden tones\",\n    \"highlights\": \"soft bloom on UI edges and grass tips\",\n    \"shadows\": \"gentle, elongated shadows under legs and flowers\"\n  },\n  \"color_palette\": {\n    \"primary\": [\"lush green\", \"warm gold\", \"soft white\"],\n    \"secondary\": [\"beige\", \"muted yellow\"],\n    \"tone\": \"warm cinematic grading with slight vintage tint\"\n  },\n  \"effects\": {\n    \"bokeh\": \"subtle light orbs floating in foreground\",\n    \"particles\": \"tiny dust/pollen particles catching sunlight\",\n    \"lens\": \"slight lens flare, soft vignette\",\n    \"atmosphere\": \"dreamy haze, cinematic softness\"\n  },\n  \"rendering\": {\n    \"style\": \"ultra-realistic, cinematic photography\",\n    \"resolution\": \"high detail, 4k\",\n    \"texture\": \"sharp fabric texture, detailed grass strands\",\n    \"dynamic_range\": \"HDR, balanced highlights and shadows\"\n  },\n  \"camera\": {\n    \"lens\": \"35mm equivalent\",\n    \"aperture\": \"f/2.8\",\n    \"iso\": 100,\n    \"shutter_speed\": \"1/500\"\n  }\n}",
